from elasticsearch import Elasticsearch

def execute_dynamic_aggregation(req):
    es = Elasticsearch()
    script_code = req['script']
    
    query = {
        "size": 0,
        "aggs": {
            "custom_agg": {
                "terms": {
                    "field": "your_field",
                    "script": {
                        "source": script_code
                    }
                }
            }
        }
    }
    
    response = es.search(index="your_index", body=query)
    return response

